// Hàm này nhận vào các tham số: công suất pin mặt trời (Wp), số giờ nắng trung bình (sunHours), hiệu suất hệ thống (efficiency), và hệ số an toàn (safetyFactor).
// Output: một object chứa các thông số tính toán được như: năng lượng có thể sản xuất (energy), công suất thực tế (actualPower), v.v.
function calculateSolarSystem(Wp, sunHours, efficiency = 0.75, safetyFactor = 1.2) {
  // Tính năng lượng trung bình mỗi ngày (Wh)
  const dailyEnergy = Wp * sunHours * efficiency;

  // Tính công suất thực tế có thể sử dụng (Wp)
  const actualPower = dailyEnergy / sunHours;

  // Tính công suất với hệ số an toàn
  const safePower = actualPower * safetyFactor;

  // Tính số lượng pin cần thiết (giả định mỗi pin 100W)
  const batteryCapacity = 100; // Wh
  const numBatteries = Math.ceil(dailyEnergy * safetyFactor / batteryCapacity);

  return {
    dailyEnergy, // Năng lượng mỗi ngày (Wh)
    actualPower, // Công suất thực tế (W)
    safePower,   // Công suất an toàn (W)
    numBatteries // Số lượng pin cần thiết
  };
}

